#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38f
#endif

__attribute__((always_inline))
float euclid_dist_2(const float *pt1,
                    const float *pt2,
                    const int numdims)
{
    float ans = 0.0f;
    for (int i = 0; i < numdims; i++) {
        float diff = pt1[i] - pt2[i];
        ans += diff * diff;
    }
    return ans;
}

__attribute__((always_inline))
int find_nearest_point(const float *pt,
                       const int nfeatures,
                       const float *clusters,
                       const int nclusters)
{
    int index = 0;
    float min_dist = FLT_MAX;

    for (int i = 0; i < nclusters; i++) {
        float dist = euclid_dist_2(pt, clusters + (i * nfeatures), nfeatures);
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }
    return index;
}

__kernel void kmeans_iteration_kernel(const float *features,
                                      int *membership,
                                      float *clusters,
                                      float *partial_new_centers,
                                      int *partial_new_centers_len,
                                      float *delta_accum,
                                      const int npoints,
                                      const int nfeatures,
                                      const int nclusters,
                                      const int start_idx,
                                      const int end_idx)
{
    float local_delta = 0.0f;

    for (int i = start_idx; i < end_idx; i++) {
        const float *pt = features + (i * nfeatures);
        int index = find_nearest_point(pt, nfeatures, clusters, nclusters);

        if (membership[i] != index) {
            local_delta += 1.0f;
        }

        membership[i] = index;

        partial_new_centers_len[index]++;
        for (int j = 0; j < nfeatures; j++) {
            partial_new_centers[index * nfeatures + j] += pt[j];
        }
    }

    delta_accum[0] += local_delta;
}
